const message = $input.first().json.chatInput || '';

// Detect Polish by diacritics or common function words
const hasPolishChars = /[ąćęłńóśźżĄĆĘŁŃÓŚŹŻ]/.test(message);
const polishWords = /\b(mam|chcę|chce|jest|są|czy|tak|nie|ile|jak|co|gdzie|kiedy|dla|bez|przy|przed|nad|pod|przez|albo|lub|więc|wiec|tylko|jeszcze|już|juz|też|tez|może|moze|proszę|prosze|dzisiaj|dziś|dzis|rynek|kupić|kupic|sprzedać|sprzedac|akcje|zysk|strata|budżet|budzet|pokaż|pokaz|szukaj|sprawdz|sprawdz|zeskanuj|hej|cześć|czesc|witaj|dobra|dobrze)\b/i;

const isPolish = hasPolishChars || polishWords.test(message);
const detectedLanguage = isPolish ? 'POLISH' : 'ENGLISH';

return [{
  json: {
    ...$input.first().json,
    chatInput: message,
    detectedLanguage
  }
}];
